package main

import (
	"strconv"
)

func solve(n int64) int64 {
	for i := n + 1; ; i++ {
		s := strconv.FormatInt(i, 10)
		if isPalindrome(s) && isSpecial(s) {
			return i
		}
	}
}

func isPalindrome(s string) bool {
	for i := 0; i < len(s)/2; i++ {
		if s[i] != s[len(s)-1-i] {
			return false
		}
	}
	return true
}

func isSpecial(s string) bool {
	count := make(map[rune]int)
	for _, c := range s {
		count[c]++
	}
	for k, v := range count {
		digit := int(k - '0')
		if v != digit {
			return false
		}
	}
	// Check that all digits present are exactly 1..m where m is the max digit
	maxDigit := 0
	for k := range count {
		digit := int(k - '0')
		if digit > maxDigit {
			maxDigit = digit
		}
	}
	// Ensure digits 1..maxDigit are all present
	for d := 1; d <= maxDigit; d++ {
		if _, ok := count[rune(d+'0')]; !ok {
			return false
		}
	}
	return true
}
